   300→				username = '';
   301→			}
   302→
   303→			const toPid = button.is('[component="post/reply"]') ? getData(button, 'data-pid') : null;
   304→			const isQuoteToPid = !toPid || !selectedNode.pid || toPid === selectedNode.pid;
   305→
   306→			if (selectedNode.text && isQuoteToPid) {
   307→				username = username || selectedNode.username;
