   353→	async function getSelectedNode() {
   354→		let selectedText = '';
   355→		let selectedPid;
   356→		let username = '';
   357→		const selection = window.getSelection ? window.getSelection() : document.selection.createRange();
   358→		const postContents = $('[component="post"] [component="post/content"]');
   359→		let content;
   360→		postContents.each(function (index, el) {
   361→			if (selection && selection.containsNode && el && selection.containsNode(el, true)) {
   362→				content = el;
   363→			}
   364→		});
   365→
   366→		if (content && selection) {
   367→			selectedText = selection.toString();
   368→			const postEl = $(content).parents('[component="post"]');
   369→			selectedPid = postEl.attr('data-pid');
