        // FIX: Call update() after async content renders
        const bsDropdown = bootstrap.Dropdown.getInstance(el.find('.dropdown-toggle').get(0));
        if (bsDropdown) {
            bsDropdown.update();  // <-- This recalculates positioning
        }
    });
}
```

